sql:
SELECT model_name 
FROM detection_models
WHERE model_id = 1;

SELECT model_name
FROM detection_models
WHERE accuracy > (SELECT AVG(accuracy) FROM detection_models);

SELECT COUNT(*)
FROM tags
WHERE tag_type = 'RFID';

SELECT COUNT(*)
   FROM detection_history
   WHERE result = 'successful';

SELECT config_id, result, detection_time, processing_time
FROM detection_history
ORDER BY detection_time DESC;

SELECT timestamp, tag_id
FROM detection_history
ORDER BY timestamp DESC;

SELECT tag_name, description 
FROM tags 
WHERE tag_id > 100;

SELECT detection_models.model_name, model_usage_logs.model_performance, model_usage_logs.detection_id
FROM detection_models
LEFT JOIN model_usage_logs ON detection_models.model_id = model_usage_logs.model_id;

SELECT * 
FROM tag_detection_configs
WHERE quality = 'High' AND allowed_tag_orientations LIKE '%portrait%';

SELECT username
FROM users
WHERE failed_login_attempts = (
    SELECT MAX(failed_login_attempts)
    FROM users
);

SELECT DISTINCT T1.tag_type 
FROM tags AS T1
INNER JOIN detection_history AS T2 ON T1.tag_id = T2.tag_id;

